@Composable
fun Greeting(name: String) {
    Text("Hello $name")
}

// Ý tưởng sau compiler transform, không phải API để tự viết:
fun Greeting(name: String, composer: Composer, changed: Int) {
    composer.startRestartGroup(/* key */)
    Text("Hello $name", composer, /* changed mask */)
    composer.endRestartGroup()
}

data class CounterUiState(
    val count: Int,
    val canDecrease: Boolean
)

@Composable
fun CounterScreen(
    state: CounterUiState,
    onIncrease: () -> Unit,
    onDecrease: () -> Unit
) {
    Column {
        Text(text = state.count.toString())
        Row {
            Button(onClick = onDecrease, enabled = state.canDecrease) {
                Text("-")
            }
            Button(onClick = onIncrease) {
                Text("+")
            }
        }
    }
}

@Composable
fun ExpandableDescription(text: String) {
    var expanded by remember { mutableStateOf(false) }

    Column {
        Text(
            text = text,
            maxLines = if (expanded) Int.MAX_VALUE else 3
        )
        TextButton(onClick = { expanded = !expanded }) {
            Text(if (expanded) "Thu gọn" else "Xem thêm")
        }
    }
}

@Composable
fun OpportunityRoute(
    viewModel: OpportunityViewModel,
    onOpenDetail: (String) -> Unit
) {
    val state by viewModel.uiState.collectAsStateWithLifecycle()

    OpportunityScreen(
        state = state,
        onRetry = viewModel::retry,
        onOpportunityClick = onOpenDetail
    )
}

@Composable
fun OpportunityScreen(
    state: OpportunityUiState,
    onRetry: () -> Unit,
    onOpportunityClick: (String) -> Unit
) {
    LazyColumn {
        items(state.items, key = { it.id }) { item ->
            OpportunityRow(item, onClick = { onOpportunityClick(item.id) })
        }
    }
}

@Composable
fun EditablePeople(people: List<Person>) {
    Column {
        people.forEach { person ->
            key(person.id) {
                var draft by remember { mutableStateOf(person.name) }
                OutlinedTextField(
                    value = draft,
                    onValueChange = { draft = it }
                )
            }
        }
    }
}
